// Stack and queue via a single array-backed deque
class Deque<T> {
  private items: T[] = [];
  pushBack(x: T) { this.items.push(x); }
  pushFront(x: T) { this.items.unshift(x); }      // O(n) - avoid in hot loops
  popBack(): T | undefined { return this.items.pop(); }
  popFront(): T | undefined { return this.items.shift(); } // O(n) - avoid
  get size() { return this.items.length; }
}
// For O(1) front ops at scale, use a ring buffer or a linked-list deque
// instead of Array.shift/unshift, which are O(n).

// Top-K largest elements with a bounded min-heap: O(n log k) time, O(k) space
int[] topK(int[] nums, int k) {
    PriorityQueue<Integer> heap = new PriorityQueue<>(); // min-heap
    for (int x : nums) {
        heap.offer(x);
        if (heap.size() > k) heap.poll(); // evict the smallest
    }
    int[] out = new int[k];
    for (int i = k - 1; i >= 0; i--) out[i] = heap.poll();
    return out;
}

from collections import deque

def bfs_shortest(graph, start, goal):
    # graph: dict[node] -> list[neighbor]; unweighted shortest path
    seen = {start}
    q = deque([(start, 0)])
    while q:
        node, dist = q.popleft()
        if node == goal:
            return dist
        for nxt in graph[node]:
            if nxt not in seen:
                seen.add(nxt)          # mark on enqueue, not dequeue,
                q.append((nxt, dist + 1))  # to avoid duplicate work
    return -1  # unreachable

// Longest substring without repeating characters: O(n) sliding window
function lengthOfLongestSubstring(s: string): number {
  const lastSeen = new Map<string, number>();
  let left = 0, best = 0;
  for (let right = 0; right < s.length; right++) {
    const c = s[right];
    if (lastSeen.has(c) && lastSeen.get(c)! >= left) {
      left = lastSeen.get(c)! + 1; // jump past the previous duplicate
    }
    lastSeen.set(c, right);
    best = Math.max(best, right - left + 1);
  }
  return best;
}

