function dedupe(posts: Post[]): Post[] {
  const out: Post[] = [];
  for (const p of posts) {
    if (!out.some(q => q.id === p.id)) { // O(n) scan inside O(n) loop
      out.push(p);
    }
  }
  return out; // total: O(n^2)
}

// AFTER: O(n) with a Set, p99 back to ~30ms
function dedupe(posts: Post[]): Post[] {
  const seen = new Set<string>();
  const out: Post[] = [];
  for (const p of posts) {
    if (!seen.has(p.id)) {  // O(1) average
      seen.add(p.id);
      out.push(p);
    }
  }
  return out;
}

