class Node {
  constructor(public key: number, public val: number,
              public prev: Node | null = null,
              public next: Node | null = null) {}
}

class LRUCache {
  private map = new Map<number, Node>();
  private head: Node; // dummy: most-recently-used side
  private tail: Node; // dummy: least-recently-used side

  constructor(private capacity: number) {
    this.head = new Node(0, 0);
    this.tail = new Node(0, 0);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private remove(n: Node) {
    n.prev!.next = n.next;
    n.next!.prev = n.prev;
  }

  private addFront(n: Node) {
    n.next = this.head.next;
    n.prev = this.head;
    this.head.next!.prev = n;
    this.head.next = n;
  }

  get(key: number): number {
    const n = this.map.get(key);
    if (!n) return -1;
    this.remove(n);      // detach
    this.addFront(n);    // mark most-recently-used
    return n.val;
  }

  put(key: number, value: number): void {
    const existing = this.map.get(key);
    if (existing) {
      existing.val = value;
      this.remove(existing);
      this.addFront(existing);
      return;
    }
    if (this.map.size >= this.capacity) {
      const lru = this.tail.prev!;   // node just before tail sentinel
      this.remove(lru);
      this.map.delete(lru.key);
    }
    const node = new Node(key, value);
    this.map.set(key, node);
    this.addFront(node);
  }
}

class ListNode {
  val: number;
  next: ListNode | null = null;
  constructor(val: number) { this.val = val; }
}

function hasCycle(head: ListNode | null): boolean {
  let slow = head;
  let fast = head;
  while (fast !== null && fast.next !== null) {
    slow = slow!.next;        // one step
    fast = fast.next.next;    // two steps
    if (slow === fast) {      // pointers met -> cycle exists
      return true;
    }
  }
  return false;               // fast ran off the end -> no cycle
}

// Optional: find the cycle's start node after a meeting.
function cycleStart(head: ListNode | null): ListNode | null {
  let slow = head, fast = head;
  while (fast && fast.next) {
    slow = slow!.next;
    fast = fast.next.next;
    if (slow === fast) {
      let p = head;
      while (p !== slow) { p = p!.next; slow = slow!.next; }
      return p; // node where the cycle begins
    }
  }
  return null;
}
